// Extract and validate incoming webhook payload.
// Expected fields:
//   listing_id: string (UUID) — shop_marketplace_listings row
//   action: 'publish' | 'update' | 'remove'
//   connection_id: string (UUID) — shop_marketplace_connections row
//   publish_payload?: object — product data for publish/update

const body = $('Webhook').first().json.body;

if (!body.listing_id || !body.action || !body.connection_id) {
  throw new Error(`Missing required fields: listing_id=${body.listing_id}, action=${body.action}, connection_id=${body.connection_id}`);
}

const validActions = ['publish', 'update', 'remove'];
if (!validActions.includes(body.action)) {
  throw new Error(`Invalid action: ${body.action}. Must be one of: ${validActions.join(', ')}`);
}

return {
  listing_id: body.listing_id,
  action: body.action,
  connection_id: body.connection_id,
  publish_payload: body.publish_payload || null,
};

// Fetch listing + decrypted connection credentials from Supabase.
// Two requests:
//   1. shop_marketplace_listings — listing data + external_listing_id
//   2. shop_marketplace_connections_decrypted — decrypted access/refresh tokens + marketplace type

const Sentry = require('@sentry/node');
const https = require('https');

const input = $('Extract Payload').first().json;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

async function supabaseGet(table, filterKey, filterValue, select) {
  const params = new URLSearchParams();
  params.append(filterKey, `eq.${filterValue}`);
  if (select) params.append('select', select);
  params.append('limit', '1');

  const url = `${SUPABASE_URL}/rest/v1/${table}?${params.toString()}`;

  return new Promise((resolve, reject) => {
    const req = https.request(url, {
      method: 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
      }
    }, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); } catch (e) { reject(new Error(`Parse error: ${body}`)); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

try {
  // 1. Fetch listing
  const listings = await supabaseGet(
    'shop_marketplace_listings',
    'id', input.listing_id,
    'id,product_id,connection_id,marketplace,external_listing_id,status,marketplace_params,marketplace_category_id,marketplace_location'
  );
  if (!listings.length) throw new Error(`Listing not found: ${input.listing_id}`);
  const listing = listings[0];

  // 2. Fetch decrypted credentials
  const connections = await supabaseGet(
    'shop_marketplace_connections_decrypted',
    'id', input.connection_id,
    'id,marketplace,access_token,refresh_token,token_expires_at,account_id'
  );
  if (!connections.length) throw new Error(`Connection not found: ${input.connection_id}`);
  const connection = connections[0];

  return {
    listing_id: listing.id,
    product_id: listing.product_id,
    external_listing_id: listing.external_listing_id || null,
    marketplace: connection.marketplace,
    access_token: connection.access_token,
    refresh_token: connection.refresh_token || null,
    token_expires_at: connection.token_expires_at || null,
    marketplace_params: listing.marketplace_params || {},
    marketplace_category_id: listing.marketplace_category_id || null,
    marketplace_location: listing.marketplace_location || null,
    action: input.action,
    publish_payload: input.publish_payload,
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// OLX API dispatcher — handles publish / update / remove.
// OLX REST API: https://developer.olx.pl/api/doc
// Auth: Bearer access_token in Authorization header
//
// Credential reconnect needed after import:
//   No n8n credential used here — token from DB decrypted view.

const Sentry = require('@sentry/node');
const https = require('https');

const input = $('Fetch Listing + Credentials').first().json;
const publish_payload = $('Extract Payload').first().json.publish_payload;

const OLX_API = 'https://www.olx.pl/api/partner';
const token = input.access_token;

async function olxRequest(method, path, body) {
  const url = `${OLX_API}${path}`;
  const bodyStr = body ? JSON.stringify(body) : null;

  return new Promise((resolve, reject) => {
    const options = {
      method,
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json',
        'Version': '2.0',
      },
    };

    const req = https.request(url, options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const parsed = data ? JSON.parse(data) : {};
          resolve({ status: res.statusCode, body: parsed });
        } catch (e) {
          resolve({ status: res.statusCode, body: data });
        }
      });
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

try {
  let result;

  if (input.action === 'remove') {
    if (!input.external_listing_id) throw new Error('Cannot remove listing: external_listing_id is missing');
    result = await olxRequest('DELETE', `/offers/${input.external_listing_id}`, null);
    if (result.status >= 400) throw new Error(`OLX remove failed: HTTP ${result.status} — ${JSON.stringify(result.body)}`);
    return { success: true, action: 'remove', marketplace: 'olx' };
  }

  if (!publish_payload) throw new Error('publish_payload required for publish/update action');

  // Build OLX offer body from publish_payload + marketplace_params
  const params = input.marketplace_params || {};
  const offerBody = {
    advertiser_type: 'private',
    contact: publish_payload.contact || {},
    description: { networking: false },
    external_id: input.listing_id,
    images: (publish_payload.images || []).map((url) => ({ url })),
    price: {
      currency: publish_payload.currency || 'PLN',
      negotiable: params.negotiable || false,
      type: 'fixed',
      value: Math.round((publish_payload.price || 0) * 100),
    },
    title: publish_payload.title,
    category: { id: parseInt(input.marketplace_category_id || params.category_id || '0', 10) },
    location: input.marketplace_location
      ? {
          city_id: input.marketplace_location.city_id,
          district_id: input.marketplace_location.district_id || null,
          lat: input.marketplace_location.lat || null,
          lon: input.marketplace_location.lon || null,
        }
      : undefined,
    attributes: params.attributes || [],
  };

  if (input.action === 'update' && input.external_listing_id) {
    result = await olxRequest('PUT', `/offers/${input.external_listing_id}`, offerBody);
  } else {
    result = await olxRequest('POST', '/offers', offerBody);
  }

  if (result.status >= 400) {
    throw new Error(`OLX ${input.action} failed: HTTP ${result.status} — ${JSON.stringify(result.body)}`);
  }

  const externalId = result.body.id?.toString() || input.external_listing_id || null;
  const externalUrl = result.body.url || null;

  return {
    success: true,
    action: input.action,
    marketplace: 'olx',
    external_listing_id: externalId,
    external_url: externalUrl,
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// Allegro API dispatcher — handles publish / update / remove.
// Allegro REST API: https://developer.allegro.pl/documentation
// Auth: Bearer access_token in Authorization header
// Note: removeListing uses PATCH with publication.status='END' (not HTTP DELETE)
//
// Credential reconnect needed after import:
//   No n8n credential used here — token from DB decrypted view.

const Sentry = require('@sentry/node');
const https = require('https');

const input = $('Fetch Listing + Credentials').first().json;
const publish_payload = $('Extract Payload').first().json.publish_payload;

const ALLEGRO_API = 'https://api.allegro.pl';
const token = input.access_token;

async function allegroRequest(method, path, body) {
  const url = `${ALLEGRO_API}${path}`;
  const bodyStr = body ? JSON.stringify(body) : null;

  return new Promise((resolve, reject) => {
    const options = {
      method,
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/vnd.allegro.public.v1+json',
        'Accept': 'application/vnd.allegro.public.v1+json',
      },
    };

    const req = https.request(url, options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const parsed = data ? JSON.parse(data) : {};
          resolve({ status: res.statusCode, body: parsed });
        } catch (e) {
          resolve({ status: res.statusCode, body: data });
        }
      });
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

try {
  let result;

  if (input.action === 'remove') {
    if (!input.external_listing_id) throw new Error('Cannot remove listing: external_listing_id is missing');
    // Allegro uses PATCH with publication.status='END' — no HTTP DELETE
    result = await allegroRequest('PATCH', `/sale/offers/${input.external_listing_id}`, {
      publication: { status: 'END' }
    });
    if (result.status >= 400) throw new Error(`Allegro remove failed: HTTP ${result.status} — ${JSON.stringify(result.body)}`);
    return { success: true, action: 'remove', marketplace: 'allegro' };
  }

  if (!publish_payload) throw new Error('publish_payload required for publish/update action');

  const params = input.marketplace_params || {};

  // Build Allegro offer object
  const offerBody = {
    name: publish_payload.title,
    description: {
      sections: [
        {
          items: [
            { type: 'TEXT', content: publish_payload.description || '' }
          ]
        }
      ]
    },
    category: { id: input.marketplace_category_id || params.category_id },
    images: (publish_payload.images || []).map((url) => ({ url })),
    sellingMode: {
      format: 'ADVERTISEMENT',
      price: {
        amount: (publish_payload.price || 0).toFixed(2),
        currency: publish_payload.currency || 'PLN',
      }
    },
    location: input.marketplace_location
      ? {
          city: input.marketplace_location.city || '',
          postCode: input.marketplace_location.postCode || '',
          province: { id: input.marketplace_location.province_id || '' },
          countryCode: { id: 'PL' },
        }
      : undefined,
    delivery: params.delivery || { shippingRates: { id: null }, handlingTime: 'PT0S' },
    payments: params.payments || { invoice: 'NO_INVOICE' },
    afterSalesServices: params.afterSalesServices || {},
    parameters: params.attributes || [],
    publication: { status: 'ACTIVE' },
  };

  if (input.action === 'update' && input.external_listing_id) {
    result = await allegroRequest('PUT', `/sale/offers/${input.external_listing_id}`, offerBody);
  } else {
    result = await allegroRequest('POST', '/sale/offers', offerBody);
  }

  if (result.status >= 400) {
    throw new Error(`Allegro ${input.action} failed: HTTP ${result.status} — ${JSON.stringify(result.body)}`);
  }

  const externalId = result.body.id?.toString() || input.external_listing_id || null;
  const externalUrl = externalId ? `https://allegro.pl/oferta/${externalId}` : null;

  return {
    success: true,
    action: input.action,
    marketplace: 'allegro',
    external_listing_id: externalId,
    external_url: externalUrl,
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// Unsupported marketplace fallback — routes to error callback.
const input = $('Fetch Listing + Credentials').first().json;
return {
  listing_id: input.listing_id,
  error_message: `Unsupported marketplace: ${input.marketplace}`,
};

// Merge success results from OLX / Allegro branches.
// Only one branch will have produced items — others are empty.

const Sentry = require('@sentry/node');

const input = $('Extract Payload').first().json;
let apiResult = null;

try {
  const branches = [
    'OLX API Call',
    'Allegro API Call',
  ];

  for (const branch of branches) {
    try {
      const items = $(branch).all();
      if (items.length > 0) {
        apiResult = items[0].json;
        break;
      }
    } catch (e) {
      // Branch not executed — skip
    }
  }

  if (!apiResult) throw new Error('No marketplace API branch produced output');

  const payload = {
    listing_id: input.listing_id,
    action: input.action,
    result: 'success',
  };

  if (apiResult.external_listing_id !== undefined) {
    payload.external_listing_id = apiResult.external_listing_id;
  }
  if (apiResult.external_url !== undefined) {
    payload.external_url = apiResult.external_url;
  }

  return payload;
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// Error handler — called when any branch throws.
// Sends failure callback to CMS.

const Sentry = require('@sentry/node');

const input = $('Extract Payload').first().json;

// Try to get error from current input, fallback to unknown
let errorMessage;
try {
  const errorItem = $input.first().json;
  errorMessage =
    errorItem?.error?.message ||
    errorItem?.message ||
    errorItem?.error ||
    'Unknown error in Marketplace Publish workflow';
} catch {
  errorMessage = 'Unknown error in Marketplace Publish workflow';
}

Sentry.captureException(new Error(`[Marketplace Publish] Failed: ${errorMessage}`));
await Sentry.flush(2000);

return {
  listing_id: input.listing_id,
  action: input.action,
  result: 'error',
  error_message: errorMessage,
};
